  1	import { ActionGroup, Button, Form, FormGroup, Panel, PanelMain, PanelMainBody } from '@patternfly/react-core';
  2	import React from 'react';
  3	import { useTranslation } from 'react-i18next';
  4	import { Config } from '../../../model/config';
  5	import { FilterCompare, FilterDefinition, Filters, FilterValue } from '../../../model/filters';
  6	import { Indicator } from '../../../utils/filters-helper';
  7	import { Direction } from '../filters-toolbar';
  8	import AutocompleteFilter from './autocomplete-filter';
  9	import CompareFilter from './compare-filter';
 10	import { FilterHints } from './filter-hints';
 11	import FiltersDropdown from './filters-dropdown';
 12	import TextFilter from './text-filter';
 13	
 14	export interface FilterSearchPanelProps {
 15	  config: Config;
 16	  filterDefinitions: FilterDefinition[];
 17	  direction: Direction;
 18	  setDirection: (direction: Direction) => void;
 19	  filter: FilterDefinition;
 20	  setFilter: (filter: FilterDefinition | null | undefined) => void;
 21	  filters?: Filters;
 22	  compare: FilterCompare;
 23	  setCompare: (compare: FilterCompare) => void;
 24	  addFilter: (filter: FilterValue) => boolean;
 25	  addFilterFromSuggestions: () => void;
 26	  setMessage: (message: string | undefined) => void;
 27	  indicator: Indicator;
 28	  setIndicator: (indicator: Indicator) => void;
 29	  value: string;
 30	  setValue: (value: string) => void;
 31	  reset: () => void;
 32	}
 33	
 34	export const FilterSearchPanel: React.FC<FilterSearchPanelProps> = ({
 35	  config,
 36	  filterDefinitions,
 37	  direction,
 38	  setDirection,
 39	  filter,
 40	  setFilter,
 41	  filters,
 42	  compare,
 43	  setCompare,
 44	  addFilter,
 45	  addFilterFromSuggestions,
 46	  setMessage,
 47	  indicator,
 48	  setIndicator,
 49	  value,
 50	  setValue,
 51	  reset
 52	}) => {
 53	  const { t } = useTranslation('plugin__netobserv-plugin');
 54	
 55	  return (
 56	    <Panel variant="raised">
 57	      <PanelMain>
 58	        <PanelMainBody>
 59	          <Form>
 60	            <FormGroup label={t('Filter')} fieldId="field" key="field">
 61	              <FiltersDropdown
 62	                config={config}
 63	                filterDefinitions={filterDefinitions}
 64	                selectedDirection={direction}
 65	                setSelectedDirection={setDirection}
 66	                selectedFilter={filter}
 67	                setSelectedFilter={setFilter}
 68	                match={filters?.match}
 69	              />
 70	              <FilterHints def={filter} />
 71	            </FormGroup>
 72	            <FormGroup label={t('Comparator')} fieldId="compare" key="compare">
 73	              <CompareFilter value={compare} setValue={setCompare} component={filter.component} />
 74	            </FormGroup>
 75	            <FormGroup label={t('Value')} fieldId="value" key="value">
 76	              {filter.component === 'autocomplete' ? (
 77	                <AutocompleteFilter
 78	                  filterDefinition={filter}
 79	                  addFilter={addFilter}
 80	                  setMessage={setMessage}
 81	                  indicator={indicator}
 82	                  setIndicator={setIndicator}
 83	                  currentValue={value}
 84	                  setCurrentValue={setValue}
 85	                />
 86	              ) : (
 87	                <TextFilter
 88	                  filterDefinition={filter}
 89	                  addFilter={addFilter}
 90	                  setMessage={setMessage}
 91	                  indicator={indicator}
 92	                  setIndicator={setIndicator}
 93	                  allowEmpty={compare !== FilterCompare.moreThanOrEqual}
 94	                  regexp={filter.component === 'number' ? /\D/g : undefined}
 95	                  currentValue={value}
 96	                  setCurrentValue={setValue}
 97	                />
 98	              )}
 99	            </FormGroup>
100	            <ActionGroup className="filters-actions">
101	              <Button id="reset-form-filter" variant="link" onClick={reset}>
102	                {t('Reset')}
103	              </Button>
104	              <Button
105	                id="add-form-filter"
106	                variant="primary"
107	                onClick={e => {
108	                  e.preventDefault();
109	                  addFilterFromSuggestions();
110	                }}
111	              >
112	                {t('Add filter')}
113	              </Button>
114	            </ActionGroup>
115	          </Form>
116	        </PanelMainBody>
117	      </PanelMain>
118	    </Panel>
119	  );
120	};

